macro.implementation:
do {
  osalSysLockFromISR();
  osalThreadResumeI(&(adcp)->thread, MSG_OK);
  osalSysUnlockFromISR();
} while (false)

do {
  osalSysLockFromISR();
  osalThreadResumeI(&(adcp)->thread, MSG_RESET);
  osalSysUnlockFromISR();
} while (false)

do {
  if ((adcp)->grpp->circular) {
    (adcp)->events |= ADC_EVENT_FULL;
    __cbdrv_invoke_full_cb(adcp);
  }
  else {
    adc_lld_stop_conversion(adcp);
    (adcp)->events |= ADC_EVENT_COMPLETE;
    __cbdrv_invoke_cb_with_transition(adcp,
                                      HAL_DRV_STATE_COMPLETE,
                                      HAL_DRV_STATE_READY);
    (adcp)->grpp = NULL;
    _adc_wakeup_isr(adcp);
  }
} while (false)

do {
  adc_lld_stop_conversion(adcp);
  (adcp)->errors |= (err);
  __cbdrv_invoke_cb_with_transition(adcp,
                                    HAL_DRV_STATE_ERROR,
                                    HAL_DRV_STATE_READY);
  (adcp)->grpp = NULL;
  _adc_error_wakeup_isr(adcp);
} while (false)

types.verbatim:
/* Including the low level driver header, it exports information required
   for completing types.*/
#include "hal_adc_lld.h"

objinit.implementation:
self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;
#if ADC_USE_WAIT == TRUE
self->thread  = NULL;
#endif

method.implementation:
msg_t msg;

osalDbgCheckClassI();
osalDbgCheck((self != NULL) && (grpp != NULL) && (samples != NULL) &&
             (depth > 0U) && ((depth == 1U) || ((depth & 1U) == 0U)));
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == HAL_DRV_STATE_ERROR),
              "not ready");

self->samples = samples;
self->depth   = depth;
self->grpp    = grpp;
self->events  = 0U;
self->errors  = 0U;
self->state   = HAL_DRV_STATE_ACTIVE;
msg = adc_lld_start_conversion(self, grpp, samples, depth);
if (msg != HAL_RET_SUCCESS) {
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
}

return msg;

msg_t msg;

osalSysLock();
msg = adcStartConversionI(self, grpp, samples, depth);
osalSysUnlock();

return msg;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == HAL_DRV_STATE_ACTIVE) ||
              (self->state == HAL_DRV_STATE_HALF) ||
              (self->state == HAL_DRV_STATE_FULL) ||
              (self->state == HAL_DRV_STATE_COMPLETE) ||
              (self->state == HAL_DRV_STATE_ERROR),
              "invalid state");

if (self->state != HAL_DRV_STATE_READY) {
  adc_lld_stop_conversion(self);
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
  _adc_reset_i(self);
}

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == HAL_DRV_STATE_ACTIVE) ||
              (self->state == HAL_DRV_STATE_HALF) ||
              (self->state == HAL_DRV_STATE_FULL) ||
              (self->state == HAL_DRV_STATE_COMPLETE) ||
              (self->state == HAL_DRV_STATE_ERROR),
              "invalid state");
if (self->state != HAL_DRV_STATE_READY) {
  adc_lld_stop_conversion(self);
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
  _adc_reset_s(self);
}
osalSysUnlock();

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->thread == NULL, "already waiting");
msg = adcStartConversionI(self, grpp, samples, depth);
if (msg == HAL_RET_SUCCESS) {
  msg = osalThreadSuspendS(&self->thread);
}
osalSysUnlock();

return msg;

adceventflags_t flags;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
flags = self->events & mask;
self->events &= ~mask;
osalSysRestoreStatusX(sts);

return flags;

adcerror_t errors;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
errors = self->errors & mask;
self->errors &= ~mask;
osalSysRestoreStatusX(sts);

return errors;

msg_t msg;

if (config != NULL) {
  self->config = __adc_setcfg_impl(self, config);
  if (self->config == NULL) {
    return HAL_RET_CONFIG_ERROR;
  }
}

self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;

msg = adc_lld_start(self);
if (msg != HAL_RET_SUCCESS) {
  self->config = NULL;
}

return msg;

adc_lld_stop(self);
self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;
